从您的描述来看，问题可能确实与`RefreshGestureScrollView`方法中项的更新逻辑有关，这是负责计算哪些项目应该显示以及如何更新它们内容的部分。让我们重写该方法，使其能够正确处理项目的显示和内容更新。

首先，您可能需要更好地处理`_items`列表中各个项目的激活状态和它们的更新。以下是一种改进方法：

```csharp
protected virtual void RefreshGestureScrollView()
{
    float contentY = scrollRect.content.anchoredPosition.y;

    // 获取首个和最后一个看到的元素的索引
    int firstVisibleIndex = Mathf.Max(0, (int)(contentY / _itemHeight));
    int lastVisibleIndex = Mathf.Min(_sourceListCount - 1, firstVisibleIndex + _visibleCount - 1);

    // 更新视图中有的items
    for(int i = 0; i < _items.Count; i++)
    {
        if(i >= _sourceListCount)
        {
            // 隐藏超出数据源数量的items
            _items[i].SetActive(false);
            continue;
        }

        if (i < firstVisibleIndex || i > lastVisibleIndex)
        {
            // 隐藏不在视野内的items
            _items[i].SetActive(false);
        }
        else
        {
            // 更新并显示视野内的items
            _items[i].SetActive(true);
            _scrollViewOperate.UpdateItemContent(i, _items[i]);
        }

        // 可以根据需要调整项目的位置
