protected virtual void RefreshGestureScrollView()
{
    // Anchor position should be non-negative
    float contentY = Mathf.Max(scrollRect.content.anchoredPosition.y, 0);

    // Calculate the range of visible items
    int startIndex = Mathf.FloorToInt(contentY / _itemHeight);
    int endIndex = Mathf.CeilToInt((contentY + _visibleHeight) / _itemHeight);
    endIndex = Mathf.Min(endIndex, _sourceListCount) - 1;

    // Check whether we have enough items in our pool, if not we need to instantiate more
    for (int i = _items.Count; i <= endIndex; ++i)
    {
        GameObject newObj = _scrollViewOperate.InitScrollViewList(i);
        LoopScrollItem newItem = new LoopScrollItem(newObj);
        _items.Add(newItem);
    }

    // Go through each item and enable or disable based on visibility
    for (int i = 0; i < _items.Count; ++i)
    {
        bool isVisible = i >= startIndex && i <= endIndex;
        _items[i].SetActive(isVisible);

        // If the item should be visible, update its content accordingly
