    float contentY = Mathf.Max(0, scrollRect.content.anchoredPosition.y);
    // 计算第一个和最后一个可见项的索引
    int firstVisibleIndex = Mathf.FloorToInt(contentY / _itemHeight);
    int invisibleCount = Mathf.FloorToInt(contentY % _itemHeight) / _itemHeight;
    int lastVisibleIndex = firstVisibleIndex + _visibleCount;
    lastVisibleIndex += invisibleCount;

    lastVisibleIndex = Mathf.Min(lastVisibleIndex, _sourceListCount); // 防止索引超出范围

    for (int i = 0; i < _items.Count; i++) {
        bool isItemVisible = i >= firstVisibleIndex && i < lastVisibleIndex;
        _items[i].SetActive(isItemVisible);

        if (isItemVisible) {
            // 更新当前可见项的内容
            _scrollViewOperate.UpdateItemContent(i, _items[i]);
        }
    }
}
